class Solution:
    def countGoodStrings(self, low: int, high: int, zero: int, one: int) -> int:
        MOD = 10**9 + 7
        dp = [[0 for _ in range(high + 1)] for _ in range(low + 1)]
        dp[0][0] = 1
        for i in range(1, low + 1):
            for j in range(high + 1):
                dp[i][j] = (dp[i - 1][j] + dp[i][j - 1]) % MOD
                if j >= zero:
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - zero]) % MOD
                if j >= one:
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - one]) % MOD
        return dp[low][high]
